package com.datamaster.module.assets.controller.admin.datasource;import cn.hutool.core.date.DateUtil;import cn.hutool.json.JSONObject;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import lombok.RequiredArgsConstructor;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.database.core.DbColumn;import com.datamaster.common.database.core.DbTable;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.StringUtils;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.module.taxonomy.api.project.dto.TaxonomyProjectReqDTO;import com.datamaster.module.taxonomy.api.project.dto.TaxonomyProjectRespDTO;import com.datamaster.module.assets.api.datasource.dto.DatasourceCreaTeTableReqDTO;import com.datamaster.module.assets.controller.admin.assetColumn.vo.AssetsAssetColumnRelRuleVO;import com.datamaster.module.assets.controller.admin.datasource.vo.AssetsDatasourcePageReqVO;import com.datamaster.module.assets.controller.admin.datasource.vo.AssetsDatasourceRespVO;import com.datamaster.module.assets.controller.admin.datasource.vo.AssetsDatasourceSaveReqVO;import com.datamaster.module.assets.controller.admin.datasource.vo.AssetsDatasourceTableVO;import com.datamaster.module.assets.convert.datasource.AssetsDatasourceConvert;import com.datamaster.module.assets.dal.dataobject.assetColumn.AssetsAssetColumnDO;import com.datamaster.module.assets.dal.dataobject.datasource.AssetsDatasourceDO;import com.datamaster.module.assets.service.asset.IAssetsAssetService;import com.datamaster.module.assets.service.datasource.IAssetsDatasourceService;import com.datamaster.module.assets.service.datasource.impl.AssetsDatasourceServiceImpl;import com.datamaster.module.standards.api.model.dto.StandardsModelColumnReqDTO;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.*;/** * 数据源Controller * * @author lhs * @date 2025-01-21 */@Tag(name = "数据源")@RestController@RequestMapping("/da/dataSource")@Validated@RequiredArgsConstructor
public class AssetsDatasourceController extends BaseController {    private final IAssetsDatasourceService AssetsDatasourceService;    private final IAssetsAssetService AssetsAssetService;    @Operation(summary = "查询数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsDatasourceRespVO>> list(AssetsDatasourcePageReqVO AssetsDatasource) {        PageResult<AssetsDatasourceDO> page = AssetsDatasourceService.getDaDatasourcePage(AssetsDatasource);        return CommonResult.success(BeanUtils.toBean(page, AssetsDatasourceRespVO.class));    }    @Operation(summary = "数据集成中排除Kafka并且是当前项目的数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:list')")    @GetMapping("/dppNoKafka/list")    public AjaxResult dppNoKafkaList(AssetsDatasourcePageReqVO AssetsDatasource) {        List<AssetsDatasourceDO> page = AssetsDatasourceService.getDaDatasourceDppNoKafka(AssetsDatasource);        return AjaxResult.success(BeanUtils.toBean(page, AssetsDatasourceRespVO.class));    }    @Operation(summary = "数据研发中的查询数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:list')")    @GetMapping("/dpp/list")    public CommonResult<PageResult<AssetsDatasourceRespVO>> dppList(AssetsDatasourcePageReqVO AssetsDatasource) {        PageResult<AssetsDatasourceDO> page = AssetsDatasourceService.getDaDatasourceDppPage(AssetsDatasource);        return CommonResult.success(BeanUtils.toBean(page, AssetsDatasourceRespVO.class));    }    @Operation(summary = "查询项目列表，让研发模块添加的数据不可选中")    @PreAuthorize("@ss.hasPermi('da:DataSource:list')")    @GetMapping("/noDppAdd/list")    public CommonResult<PageResult<TaxonomyProjectRespDTO>> noDppAddList(TaxonomyProjectReqDTO pageReqVO) {        PageResult<TaxonomyProjectRespDTO> page = AssetsDatasourceService.getNoDppAddList(pageReqVO);        return CommonResult.success(page);    }    @Operation(summary = "查询数据资产的数据源连接信息")    @PreAuthorize("@ss.hasPermi('da:asset:list')")    @GetMapping("/getDataSourceByAsset")    public AjaxResult getDataSourceByAsset(AssetsDatasourceRespVO AssetsAsset) {        List<AssetsDatasourceDO> AssetsAssetDOS = AssetsDatasourceService.getDataSourceByAsset(AssetsAsset);        return AjaxResult.success(AssetsAssetDOS);    }    @Operation(summary = "查询数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:list')")    @GetMapping("/getDaDatasourceList")    public CommonResult<List<AssetsDatasourceRespVO>> getDaDatasourceList(AssetsDatasourcePageReqVO AssetsDatasource) {        List<AssetsDatasourceDO> page = AssetsDatasourceService.getDaDatasourceList(AssetsDatasource);        return CommonResult.success(BeanUtils.toBean(page, AssetsDatasourceRespVO.class));    }    @Operation(summary = "导出数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:export')")    @Log(title = "数据源", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsDatasourcePageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsDatasourceDO> list = (List<AssetsDatasourceDO>) AssetsDatasourceService.getDaDatasourcePage(exportReqVO).getRows();        ExcelUtil<AssetsDatasourceRespVO> util = new ExcelUtil<>(AssetsDatasourceRespVO.class);        util.exportExcel(response, AssetsDatasourceConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据源列表")    @PreAuthorize("@ss.hasPermi('da:DataSource:import')")    @Log(title = "数据源", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsDatasourceRespVO> util = new ExcelUtil<>(AssetsDatasourceRespVO.class);        List<AssetsDatasourceRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsDatasourceService.importDaDatasource(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据源详细信息")    @PreAuthorize("@ss.hasPermi('da:DataSource:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsDatasourceRespVO> getInfo(@PathVariable("id") Long id) {        AssetsDatasourceDO AssetsDatasourceDO = AssetsDatasourceService.getDaDatasourceById(id);        return CommonResult.success(BeanUtils.toBean(AssetsDatasourceDO, AssetsDatasourceRespVO.class));    }    @Operation(summary = "新增数据源")    @PreAuthorize("@ss.hasPermi('da:DataSource:add')")    @Log(title = "数据源", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsDatasourceSaveReqVO AssetsDatasource) {        AssetsDatasource.setCreatorId(getUserId());        AssetsDatasource.setCreateBy(getNickName());        AssetsDatasource.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDatasourceService.createDaDatasource(AssetsDatasource));    }    @Operation(summary = "修改数据源")    @PreAuthorize("@ss.hasPermi('da:DataSource:edit')")    @Log(title = "数据源", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsDatasourceSaveReqVO AssetsDatasource) {        AssetsDatasource.setUpdatorId(getUserId());        AssetsDatasource.setUpdateBy(getNickName());        AssetsDatasource.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDatasourceService.updateDaDatasource(AssetsDatasource));    }    @Operation(summary = "删除数据源")    @PreAuthorize("@ss.hasPermi('da:DataSource:remove')")    @Log(title = "数据源", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsDatasourceService.removeDaDatasource(Arrays.asList(ids)));    }    @Operation(summary = "修改数据源状态")    @PreAuthorize("@ss.hasPermi('da:DataSource:edit')")    @GetMapping(value = "/editDatasourceStatus/{id}/{status}")    public AjaxResult editDatasourceStatus(@PathVariable Long id, @PathVariable Long status) {        Boolean isOk = AssetsDatasourceService.editDatasourceStatus(id, status);        if (!isOk) {            return AjaxResult.error("任务状态修改失败，请联系系统管理员");        }        return AjaxResult.success("修改成功");    }    @Operation(summary = "删除数据源带类型判断是数据资产还是数据研发")    @PreAuthorize("@ss.hasPermi('da:DataSource:remove')")    @Log(title = "数据源", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}/{type}")    public CommonResult<Integer> removeDppOrDa(@PathVariable("ids") Long[] ids, @PathVariable("type") Long type) {        return CommonResult.toAjax(AssetsDatasourceService.removeDaDatasourceDppOrDa(Arrays.asList(ids), type));    }    @Operation(summary = "测试连接")    @PreAuthorize("@ss.hasPermi('da:DataSource:remove')")    @Log(title = "测试连接", businessType = BusinessType.DELETE)    @GetMapping("clientsTest/{id}")    public AjaxResult clientsTest(@PathVariable("id") Long ids) {        return AssetsDatasourceService.clientsTest(ids);    }    @Operation(summary = "获取数据源里面的数据表")    @PreAuthorize("@ss.hasPermi('da:DataSource:query')")    @GetMapping(value = "/tableList/{id}")    public AjaxResult getTableList(@PathVariable("id") Long id) {        List<DbTable> tables = AssetsDatasourceService.getDbTables(id);        return success(tables);    }    @Operation(summary = "获取数据源里面的数据表的数据字段")    @PreAuthorize("@ss.hasPermi('da:DataSource:query')")    @PostMapping(value = "/columnsList")    public AjaxResult getColumnsList(@RequestBody JSONObject jsonObject) {        List<StandardsModelColumnReqDTO> columns = AssetsDatasourceService.getColumnsList(jsonObject);        return success(columns);    }    @Operation(summary = "SQL解析")    @PreAuthorize("@ss.hasPermi('da:DataSource:query')")    @PostMapping("/sqlParse")    public AjaxResult sqlParse(@RequestBody JSONObject jsonObject) {        if (StringUtils.isEmpty(jsonObject.getStr("sourceId"))) {            return AjaxResult.error("请携带数据源!");        }        if (StringUtils.isEmpty(jsonObject.getStr("sql"))) {            return AjaxResult.error("请输入SQL语句!");        }       /* try {            jsonObject.set("sql",AesEncryptUtil.desEncrypt(jsonObject.getStr("sql")).trim());        } catch (Exception e) {            e.printStackTrace();        }*/        List<DbColumn> dbColumnList = AssetsDatasourceService.sqlParse(jsonObject.getStr("sourceId"), jsonObject.getStr("sql"));        List<AssetsAssetColumnDO> AssetsAssetColumnDOList = AssetsDatasourceServiceImpl.convertDbColumns(dbColumnList);        return AjaxResult.success(AssetsAssetColumnDOList);    }    @Operation(summary = "获取数据源里面的数据表的数据字段")    @PreAuthorize("@ss.hasPermi('da:DataSource:query')")    @PostMapping(value = "/columnsAsAssetColumnList")    public CommonResult<List<AssetsAssetColumnDO>> columnsAsAssetColumnList(@RequestBody @Valid AssetsDatasourceTableVO param) {        List<AssetsAssetColumnDO> columns = AssetsDatasourceService.columnsAsAssetColumnList(param.getId(), param.getTableName());        if (param.getWithRule() == null) {            return CommonResult.success(columns);        }        if (param.getWithRule() != 2 && param.getWithRule() != 1) {            return CommonResult.success(columns);        }        List<AssetsAssetColumnRelRuleVO> assetColumnRelRuleVOS = AssetsAssetService.listRelRule(param.getId(), param.getTableName(), param.getWithRule().toString());        if (assetColumnRelRuleVOS.isEmpty()) {            return CommonResult.success(columns);        }        columns.forEach(i -> i.setCleanRuleList(new ArrayList<>()));        for (AssetsAssetColumnRelRuleVO vo : assetColumnRelRuleVOS) {            for (AssetsAssetColumnDO column : columns) {                if (column.getColumnName().equalsIgnoreCase(vo.getAssetColumn().getColumnName())) {                    column.getCleanRuleList().add(vo.getElemRuleRel());                    break;                }            }        }        return CommonResult.success(columns);    }    @Operation(summary = "")    @PreAuthorize("@ss.hasPermi('da:DataQuery:list')")    @GetMapping(value = "/executeSqlQuery")    public AjaxResult executeSqlQuery(AssetsDatasourcePageReqVO AssetsDatasource) {        return success(AssetsDatasourceService.executeSqlQuery(AssetsDatasource));    }    @Operation(summary = "")    @PreAuthorize("@ss.hasPermi('da:DataQuery:list')")    @GetMapping(value = "/exportSqlQueryResult/export")    public void exportSqlQueryResult(HttpServletResponse response, AssetsDatasourcePageReqVO AssetsDatasource) {        AssetsDatasourceService.exportSqlQueryResult(response, AssetsDatasource);    }}